import java.io.*;import java.util.*;class Main{static int solve(String[] stickers,String target){int n=stickers.length,m=target.length();int[][] counts=new int[n][26];for(int i=0;i<n;i++)for(char ch:stickers[i].toCharArray())counts[i][ch-'a']++;int[] targetIdx=new int[m];for(int i=0;i<m;i++)targetIdx[i]=target.charAt(i)-'a';int full=(1<<m)-1;int[] memo=new int[1<<m];Arrays.fill(memo,-2);int answer=dfs(0,counts,targetIdx,full,memo);return answer>=1_000_000_000?-1:answer;}static int dfs(int mask,int[][] counts,int[] targetIdx,int full,int[] memo){if(mask==full)return 0;if(memo[mask]!=-2)return memo[mask];int first=0;while(((mask>>first)&1)==1)first++;int need=targetIdx[first];int best=1_000_000_000;for(int[] base:counts){if(base[need]==0)continue;int[] remaining=base.clone();int next=mask;for(int i=0;i<targetIdx.length;i++){int ch=targetIdx[i];if(((next>>i)&1)==0&&remaining[ch]>0){remaining[ch]--;next|=1<<i;}}if(next!=mask)best=Math.min(best,1+dfs(next,counts,targetIdx,full,memo));}return memo[mask]=best;}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);String[] stickers=new String[n];for(int i=0;i<n;i++)stickers[i]=d[idx++];String target=d[idx++];if(tc>0)out.append("\n\n");out.append(solve(stickers,target));}System.out.print(out);}}
